@staff_member_required
def tasks_view(request):
    """Admin view to launch tasks."""

    if request.method == "POST":
        task_name = request.POST["task"]

        if task_name == "initialize":
            initialize_data.delay()
        elif task_name == "insert_csv":
            insert_csv.delay()
        elif task_name == "insert_enedis_hist_yearly":
            insert_enedis_yearly.delay()
        elif task_name == "insert_enedis_hist":
            insert_enedis_hist.delay()
        elif task_name == "convert_enedis_m023":
            convert_enedis_m023.delay()
        elif task_name == "validate_challenge_quiz_forms":
            validate_challenge_quiz_forms.delay()
        elif task_name == "delete_duplicates_datas_resources":
            delete_duplicates_datas_resources.delay()
        elif task_name == "upload_operat_attests":
            upload_operat_attests.delay()
        elif task_name == "upload_operat_synthesis":
            upload_operat_synthesis.delay()
        elif task_name == "correct_data":
            date_begin = request.POST.get("date_begin", None)
            date_end = request.POST.get("date_end", None)
            sensor_id = request.POST.get("sensor_id", None)

            _process_correct_data(request, sensor_id, date_begin, date_end)
        elif task_name == "fetch_m023_api":
            date_begin = request.POST.get("date_begin", None)
            date_end = request.POST.get("date_end", None)
            sensor_code = request.POST.get("sensor_code", None)
            data_type = request.POST.get("data_type", "electricity")

            if date_begin and date_end and sensor_code:
                sensors = Sensor.objects.filter(
                    code=sensor_code,
                    data_type__name__in=(
                        ["power", "electricity"]
                        if data_type == "power_electricity"
                        else [data_type]
                    ),
                )

                if not sensors.exists():
                    messages.add_message(
                        request, messages.ERROR, "Le code du capteur est incorrect"
                    )
                    return render(request, "admin/tasks/index.html")

                messages.add_message(
                    request,
                    messages.SUCCESS,
                    "Tâche de récupération de l'historique M023 en cours",
                )
                fetch_m023_api.delay(
                    list(sensors.values_list("id", flat=True)), date_begin, date_end
                )
            else:
                messages.add_message(
                    request,
                    messages.ERROR,
                    "Veuillez renseigner les dates et le code du capteur",
                )

    return render(request, "admin/tasks/index.html")


def _process_correct_data(request, sensor_id, date_begin, date_end):
    sensor = get_or_none(Sensor, id=sensor_id)

    if not sensor:
        messages.add_message(request, messages.ERROR, "L'id du capteur est incorrect")
        return

    if not date_begin or not date_end:
        messages.add_message(
            request, messages.ERROR, "Veuillez renseigner les dates de début et de fin"
        )
        return

    if date_begin > date_end:
        messages.add_message(
            request,
            messages.ERROR,
            "La date de début doit être inférieure à la date de fin",
        )
        return

    messages.add_message(
        request,
        messages.SUCCESS,
        f"Tâche de correction des données en cours pour {sensor.code}",
    )

    date_begin = arrow.get(date_begin)
    date_end = arrow.get(date_end)

    correct_index_spike_anomaly(sensor, date_begin, date_end)


