@staff_member_required
def all_exports(request):
    """Admin view to launch export tasks."""

    if request.method == "POST":
        task_name = request.POST["task"]

        if task_name == "export_user_challenge":
            form = ExportUserChallengeForm(request.POST)
            if form.is_valid():
                export_user_challenge(request)
            else:
                return render(
                    request,
                    "admin/tasks/all_exports.html",
                    context={"export_user_challenge_form": form},
                )
        elif task_name == "export_challenge_data":
            form = ExportChallengeDataForm(request.POST)
            if form.is_valid():
                export_challenge_data(request)
            else:
                return render(
                    request,
                    "admin/tasks/all_exports.html",
                    context={"export_challenge_data_form": form},
                )
        elif task_name == "export_challenge_points":
            form = ExportChallengePointsForm(request.POST)
            if form.is_valid():
                export_challenge_points(request)
            else:
                return render(
                    request,
                    "admin/tasks/all_exports.html",
                    context={"export_challenge_points_form": form},
                )

    return render(
        request,
        "admin/tasks/all_exports.html",
        {
            "export_user_challenge_form": ExportUserChallengeForm(),
            "export_challenge_data_form": ExportChallengeDataForm(),
            "export_challenge_points_form": ExportChallengePointsForm(),
        },
    )


@staff_member_required
def tasks_state(request):
    """Fetch active and reserved tasks from celery and display it as a list"""

    # Additional data sent to html with empty state
    data = {
        "active_tasks": ["Aucune tâche active"],
        "reserved_tasks": ["Aucune tâche en attente"],
    }

    # The counters of hidden tasks which are usually automated tasks
    cnt_hidden_active_tasks = 0
    cnt_hidden_reserved_tasks = 0
    try:
        # The celery inspector that can access workers informations
        inspector = current_app.control.inspect()

        # If inspector is None, celery is not accessible
        if inspector is None:
            data = {
                "active_tasks": ["La liste des tâches n'est pas accessible actuellement"],
                "reserved_tasks": [],
            }
            raise Exception

        # CURRENT TASKS
        current_worker_tasks = []

        # Fetch the active tasks, data is returned as for each worker has its active tasks
        active_tasks = inspector.active()

        for worker in active_tasks:
            # The list of tasks for the worker
            tasks = active_tasks[worker]

            for task in tasks:
                # The name is usually egreen.lib.[...], only take the last part ie the task name
                task_name = task["name"].split(".")[-1]

                # Sometimes, additional text will be added like the building etc...
                additional_text = "| "

                # If the task name is not in the list, then it is not interesting for the project people
                # But it is still important to acknowledge that a task is running currently
                if task_name not in interesting_tasks:
                    cnt_hidden_active_tasks += 1
                    continue
                else:
                    try:
                        # In the case of a reference compute for the sensors, fetch the building to display
                        if task_name == "compute_and_set_references":
                            # The argument of the task is a list of sensor for the building, but only need one
                            sensor_id = task["args"][0][0]

                            building = Building.objects.get(sensors=sensor_id)
                            additional_text += building.name
                        # In the case of a terdecree compute, fetch the building and display its name
                        elif task_name == "create_terdecree_from_building":
                            # The only argument of the task is the building id
                            building_id = task["args"][0]
                            building = Building.objects.get(id=building_id)
                            additional_text += building.name
                    except Exception:
                        pass
                # Append the informations formatted in a comprehensible way
                current_worker_tasks.append(
                    "{} | {} {}".format(task_name, task["args"], additional_text)
                )
        if current_worker_tasks:
            data["active_tasks"] = current_worker_tasks

        # TASKS RESERVED
        reserved_worker_tasks = []

        # Fetch the reserved tasks, data is returned as for each worker has its active tasks
        reserved_tasks = inspector.reserved()
        for worker in reserved_tasks:
            # The list of tasks for the worker
            tasks = reserved_tasks[worker]
            for task in tasks:
                # The name is usually egreen.lib.[...], only take the last part ie the task name
                task_name = task["name"].split(".")[-1]

                # Sometimes, additional text will be added like the building etc...
                additional_text = "| "

                # If the task name is not in the list, then it is not interesting for the project people
                # But it is still important to acknowledge that a task is running currently
                if task_name not in interesting_tasks:
                    cnt_hidden_reserved_tasks += 1
                    continue
                else:
                    try:
                        # In the case of a reference compute for the sensors, fetch the building to display
                        if task_name == "compute_and_set_references":
                            # The argument of the task is a list of sensor for the building, but only need one
                            sensor_id = task["args"][0][0]
                            building = Building.objects.get(sensors=sensor_id)
                            additional_text += building.name
                        # In the case of a terdecree compute, fetch the building and display its name
                        elif task_name == "create_terdecree_from_building":
                            # The only argument of the task is the building id
                            building_id = task["args"][0]
                            building = Building.objects.get(id=building_id)
                            additional_text += building.name
                    except Exception:
                        pass
                # Append the informations formatted in a comprehensible way
                reserved_worker_tasks.append(
                    "{} | {} {}".format(task["name"].split(".")[-1], task["args"], additional_text)
                )
        if reserved_worker_tasks:
            data["reserved_tasks"] = reserved_worker_tasks

        if len(data["active_tasks"]) == 0 and cnt_hidden_active_tasks > 0:
            data["active_tasks"] = [
                "{} tâches automatisées en cours d'exécution".format(cnt_hidden_active_tasks)
            ]

        if len(data["reserved_tasks"]) == 0 and cnt_hidden_reserved_tasks > 0:
            data["reserved_tasks"] = [
                "{} tâches automatisées en attente".format(cnt_hidden_reserved_tasks)
            ]
    except Exception:
        pass
    return render(request, "admin/tasks/index_state.html", data)


class JSONFieldFilter(admin.SimpleListFilter):
    """
    Base JSONFilter class to use by individual attribute filter classes.
    e.g  data in JSON field
    {
        "name": "Gaurav",
        "company": "pyscoop",
        "address": {
            "city": "Jaipur",
            "country": {"name": "India", "code": "IN"}
        }
    }
    """

    model_json_field_name = None  # name of the json field column in the model
    json_data_property_name = None  # name of one attribute from json data

    def get_child_value_from_json_field_data(self, json_field_data):
        key_list = self.json_data_property_name.split("__")
        for key in key_list:
            if isinstance(json_field_data, dict):
                json_field_data = json_field_data.get(key, None)

        return json_field_data

    def lookups(self, request, model_admin):
        """
        Returns a list of tuples.
        The first element in each tuple is the coded value for the option that will appear in the URL query.
        The 2nd element is the human-readable name for the option that will appear in the right sidebar.
        """
        if self.model_json_field_name is None:
            raise ImproperlyConfigured(
                f'Filter class {self.__class__.__name__} does not specify "model_json_field_name"'
            )

        if self.json_data_property_name is None:
            raise ImproperlyConfigured(
                f'Filter class {self.__class__.__name__} does not specify "json_data_property_name"'
            )

        field_value_set = set()

        for json_field_data in model_admin.model.objects.values_list(
            self.model_json_field_name, flat=True
        ):
            field_value_set.add(self.get_child_value_from_json_field_data(json_field_data))

        return [(v, v) for v in field_value_set]

    def queryset(self, request, queryset):
        """
        Returns the filtered queryset based on the value provided in the query string & retrievable via `self.value()`
        """
        if self.value():
            json_field_query = {
                f"{self.model_json_field_name}__{self.json_data_property_name}": self.value()
            }
            return queryset.filter(**json_field_query)
        else:
            return queryset
